disp("Loading Damage Dataset...") %[output:555b583b]
damagePath = 'Put the damage dataset path';
imds_damage = imageDatastore(damagePath, ...
    'IncludeSubfolders', true, ...
    'LabelSource', 'foldernames');
disp(countEachLabel(imds_damage)) %[output:497976f8]
%% IMAGE SIZE
inputSize = [224 224 3];
% Split
[train_damage, val_damage] = splitEachLabel(imds_damage, 0.8, 'randomized');
train_damage_aug = augmentedImageDatastore(inputSize, train_damage, ...
    'ColorPreprocessing','gray2rgb');
val_damage_aug = augmentedImageDatastore(inputSize, val_damage,...
    'ColorPreprocessing','gray2rgb');
% Load pretrained again
net2 = resnet18;
lgraph2 = layerGraph(net2);
numClasses_damage = numel(categories(imds_damage.Labels));
% Modify layers
lgraph2 = replaceLayer(lgraph2, 'fc1000', ...
    fullyConnectedLayer(numClasses_damage));
lgraph2 = replaceLayer(lgraph2, 'prob', softmaxLayer);
lgraph2 = replaceLayer(lgraph2, ...
    'ClassificationLayer_predictions', ...
    classificationLayer);
%% TRAIN OPTIONS
options = trainingOptions('adam', ...
    'MaxEpochs', 5, ...
    'MiniBatchSize', 16, ...
    'Verbose', false, ...
    'Plots', 'training-progress');
disp("Training Damage Model...") %[output:5f562acb]
damageNet = trainNetwork(train_damage_aug, lgraph2, options); %[output:2f144885]
damageModel = damageNet;
save('damageModel.mat', 'damageModel');



